{
  "sentences": [
    {
      "text": "今天天氣太熱了，我心情不好。",
      "pinyin": "Jīntiān tiānqì tài rè le, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 re4 le0, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is too hot today, I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 너무 더워서 기분이 안 좋아요."
    },
    {
      "text": "昨天太冷了，所以我沒有出門。",
      "pinyin": "Zuótiān tài lěng le, suǒyǐ wǒ méiyǒu chūmén.",
      "pinyin_numeric": "zuo2tian1 tai4 leng3 le0, suo3yi3 wo3 mei2you3 chu1men2.",
      "translation_en": "It was too cold yesterday, so I didn't go out.",
      "translation_ko": "어제 너무 추워서 밖에 안 나갔어요."
    },
    {
      "text": "颱風天風太大了，走路要小心。",
      "pinyin": "Táifēng tiān fēng tài dà le, zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 tai4 da4 le0, zou3lu4 yao4 xiao3xin1.",
      "translation_en": "The wind is too strong on typhoon days, be careful when walking.",
      "translation_ko": "태풍 날 바람이 너무 세서 걸을 때 조심해야 해요."
    },
    {
      "text": "這家餐廳太貴了，我們換一家吧。",
      "pinyin": "Zhè jiā cāntīng tài guì le, wǒmen huàn yī jiā ba.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 tai4 gui4 le0, wo3men huan4 yi1 jia1 ba0.",
      "translation_en": "This restaurant is too expensive, let's change to another one.",
      "translation_ko": "이 식당은 너무 비싸니까 다른 데로 갈까요?"
    },
    {
      "text": "今天下午天氣很舒服，我心情很開心。",
      "pinyin": "Jīntiān xiàwǔ tiānqì hěn shūfú, wǒ xīnqíng hěn kāixīn.",
      "pinyin_numeric": "jin1tian1 xia4wu3 tian1qi4 hen3 shu1fu2, wo3 xin1qing2 hen3 kai1xin1.",
      "translation_en": "The weather is very comfortable this afternoon, I'm in a happy mood.",
      "translation_ko": "오늘 오후 날씨가 아주 쾌적해서 기분이 좋아요."
    },
    {
      "text": "下雨天路太滑了，你走路要小心。",
      "pinyin": "Xiàyǔ tiān lù tài huá le, nǐ zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 tai4 hua2 le0, ni3 zou3lu4 yao4 xiao3xin1.",
      "translation_en": "The road is too slippery on rainy days, be careful when walking.",
      "translation_ko": "비 오는 날 길이 너무 미끄러우니까 걸을 때 조심하세요."
    },
    {
      "text": "今天三十度，太熱了，我想喝冰水。",
      "pinyin": "Jīntiān sānshí dù, tài rè le, wǒ xiǎng hē bīng shuǐ.",
      "pinyin_numeric": "jin1tian1 san1shi2 du4, tai4 re4 le0, wo3 xiang3 he1 bing1 shui3.",
      "translation_en": "It's 30 degrees today, too hot, I want to drink ice water.",
      "translation_ko": "오늘 30도라서 너무 더워요, 얼음물 마시고 싶어요."
    },
    {
      "text": "明天是晴天，天氣很好，我們去公園散步吧。",
      "pinyin": "Míngtiān shì qíngtiān, tiānqì hěn hǎo, wǒmen qù gōngyuán sànbù ba.",
      "pinyin_numeric": "ming2tian1 shi4 qing2tian1, tian1qi4 hen3 hao3, wo3men qu4 gong1yuan2 san4bu4 ba0.",
      "translation_en": "Tomorrow will be sunny, the weather is great, let's go for a walk in the park.",
      "translation_ko": "내일은 맑은 날씨라서 날씨가 좋아요, 공원에 산책하러 가요."
    },
    {
      "text": "最近壓力太大了，我需要放鬆一下。",
      "pinyin": "Zuìjìn yālì tài dà le, wǒ xūyào fàngsōng yīxià.",
      "pinyin_numeric": "zui4jin4 ya1li4 tai4 da4 le0, wo3 xu1yao4 fang4song1 yi1xia4.",
      "translation_en": "The pressure has been too great lately, I need to relax a bit.",
      "translation_ko": "요즘 스트레스가 너무 커서 좀 쉬어야 해요."
    },
    {
      "text": "今天陰天，天氣悶熱，我沒有精神。",
      "pinyin": "Jīntiān yīntiān, tiānqì mēnrè, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "jin1tian1 yin1tian1, tian1qi4 men1re4, wo3 mei2you3 jing1shen2.",
      "translation_en": "It's cloudy today, the weather is muggy, I have no energy.",
      "translation_ko": "오늘 흐리고 날씨가 후덥지근해서 기운이 없어요."
    }
  ]
}
